// src/pages/FarmEditPage.js
import React, { useState, useEffect } from 'react'; // SỬA LỖI: Đã xóa dấu phẩy thừa sau "React"
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css';
import speciesOptions from '../data/speciesData';

function FarmEditPage() {
  const { farmId } = useParams();
  const navigate = useNavigate();
  const token = localStorage.getItem('token');

  // State chính cho các trường có sẵn của form
  const [farmData, setFarmData] = useState({
    tenCoSo: '',
    tinhThanhPho: '',
    xaPhuong: '',
    diaChiCoSo: '',
    vido: '',
    kinhdo: '',
    ngayThanhLap: '',
    giayPhepKinhDoanh: '',
    tenNguoiDaiDien: '',
    namSinh: '',
    soCCCD: '',
    ngayCapCCCD: '',
    noiCapCCCD: '',
    soDienThoaiNguoiDaiDien: '',
    diaChiNguoiDaiDien: '',
    mucDichNuoi: '',
    hinhThucNuoi: '',
    maSoCoSoGayNuoi: '',
    tongDan: '',
    loaiHinhKinhDoanhGo: '',
    nganhNgheKinhDoanhGo: '',
    khoiLuong: '',
    loaiCoSoDangKy: '',
    tenLamSan: '',
    tenKhoaHoc: '',
    issueDate: '',
    expiryDate: '',
    trangThai: '',
    ghiChu: '',
  });

  const [loading, setLoading] = useState(true);
  const [errorMessage, setErrorMessage] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  
  // State cho mục đăng ký mới
  const [newSpeciesData, setNewSpeciesData] = useState({ name: '', scientificName: '' });
  const [selectedNewSpecies, setSelectedNewSpecies] = useState('');
  const [isManualEntry, setIsManualEntry] = useState(false);


  useEffect(() => {
    const fetchFarmData = async () => {
      setLoading(true);
      try {
        const response = await axios.get(`http://localhost:10000/api/farms/${farmId}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        const data = { ...response.data };

        // Định dạng lại ngày tháng
        Object.keys(data).forEach(key => {
          if (['ngayThanhLap', 'ngayCapCCCD', 'issueDate', 'expiryDate'].includes(key) && data[key]) {
            data[key] = new Date(data[key]).toISOString().split('T')[0];
          }
        });
        setFarmData(data);
      } catch (error) {
        setErrorMessage('Không thể tải dữ liệu cơ sở.');
      } finally {
        setLoading(false);
      }
    };
    if (farmId) fetchFarmData();
  }, [farmId, token]);

  // Handler cho các input của form cũ
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFarmData(prev => ({ ...prev, [name]: value }));
  };

  // Các handler cho mục đăng ký mới
  const handleNewSpeciesChange = (e) => {
    const value = e.target.value;
    setSelectedNewSpecies(value);

    // Khi chọn ở khu vực mới, xóa giá trị ở khu vực cũ để tránh nhầm lẫn
    setFarmData(prev => ({ ...prev, tenLamSan: '', tenKhoaHoc: '' }));

    if (value === 'Nhập thủ công') {
      setIsManualEntry(true);
      setNewSpeciesData({ name: '', scientificName: '' });
    } else {
      setIsManualEntry(false);
      const matched = speciesOptions.find(s => s.tenLamSan === value);
      setNewSpeciesData({
        name: matched ? matched.tenLamSan : '',
        scientificName: matched ? matched.tenKhoaHoc : '',
      });
    }
  };

  const handleManualNewSpeciesChange = (e) => {
    const { name, value } = e.target;
    setNewSpeciesData(prev => ({ ...prev, [name]: value }));
  };


  const handleSubmit = async (e) => {
    e.preventDefault();
    setErrorMessage('');
    setSuccessMessage('');
    try {
      const dataToSend = { ...farmData };

      // Logic ưu tiên dữ liệu từ mục mới
      if (newSpeciesData.name) {
        dataToSend.tenLamSan = newSpeciesData.name;
        dataToSend.tenKhoaHoc = newSpeciesData.scientificName;
      }

      await axios.put(`http://localhost:10000/api/farms/${farmId}`, dataToSend, {
          headers: { Authorization: `Bearer ${token}` }
      });
      setSuccessMessage('Cập nhật thông tin cơ sở thành công!');
    } catch (error) {
      setErrorMessage(error.response?.data?.message || 'Cập nhật thất bại.');
    }
  };

  if (loading) return <div className="form-container"><p>Đang tải...</p></div>;

  return (
    <div className="form-container">
      <h1>Chỉnh sửa thông tin cơ sở</h1>
      {successMessage && <p className="success-message">{successMessage}</p>}
      {errorMessage && <p className="error-message">{errorMessage}</p>}
      <form onSubmit={handleSubmit}>
        
        {/* === MỤC THÔNG TIN CƠ SỞ === */}
        <section className="khai-bao-section">
          <h3>Thông tin cơ sở</h3>
          {/* Ví dụ một vài trường, bạn hãy bổ sung đầy đủ các trường khác của mình */}
          <div className="form-group">
            <label htmlFor="tenCoSo">Tên cơ sở:</label>
            <input type="text" id="tenCoSo" name="tenCoSo" value={farmData.tenCoSo} onChange={handleChange} required />
          </div>
           <div className="form-group">
            <label htmlFor="diaChiCoSo">Địa chỉ cơ sở:</label>
            <input type="text" id="diaChiCoSo" name="diaChiCoSo" value={farmData.diaChiCoSo} onChange={handleChange} required />
          </div>
        </section>

        {/* === MỤC THÔNG TIN LOÀI (CẤU TRÚC CŨ) === */}
        {(farmData.loaiCoSoDangKy) && (
            <section className="khai-bao-section">
                <h3>Thông tin Loài</h3>
                <div className="form-grid">
                    <div className="form-group">
                        <label htmlFor="tenLamSan">Tên lâm sản:</label>
                        <input type="text" id="tenLamSan" name="tenLamSan" value={farmData.tenLamSan} onChange={handleChange} />
                    </div>
                    <div className="form-group">
                        <label htmlFor="tenKhoaHoc">Tên khoa học:</label>
                        <input type="text" id="tenKhoaHoc" name="tenKhoaHoc" value={farmData.tenKhoaHoc} onChange={handleChange} />
                    </div>
                </div>
            </section>
        )}

        {/* === MỤC MỚI: ĐĂNG KÝ LOÀI MỚI === */}
        {(farmData.loaiCoSoDangKy) && (
            <section className="khai-bao-section" style={{border: '2px dashed #007bff', marginTop: '20px'}}>
                <h3 style={{color: '#007bff'}}>Hoặc đăng ký / cập nhật loài mới</h3>
                <div className="form-grid">
                    <div className="form-group">
                        <label htmlFor="newSpeciesSelection">Tên lâm sản mới:</label>
                        <select 
                            id="newSpeciesSelection"
                            value={selectedNewSpecies}
                            onChange={handleNewSpeciesChange}
                        >
                            <option value="">-- Chọn hoặc nhập thủ công --</option>
                            {speciesOptions.map((option, index) => (
                                <option key={index} value={option.tenLamSan}>
                                    {option.tenLamSan}
                                </option>
                            ))}
                        </select>
                    </div>
                    
                    {!isManualEntry && selectedNewSpecies && selectedNewSpecies !== 'Nhập thủ công' && (
                        <div className="form-group">
                            <label>Tên khoa học (tự động):</label>
                            <input type="text" value={newSpeciesData.scientificName} readOnly disabled />
                        </div>
                    )}

                    {isManualEntry && (
                        <>
                            <div className="form-group">
                                <label>Tên lâm sản (nhập tay):</label>
                                <input 
                                    type="text" 
                                    name="name" 
                                    value={newSpeciesData.name} 
                                    onChange={handleManualNewSpeciesChange} 
                                    placeholder="Nhập tên lâm sản mới" 
                                />
                            </div>
                            <div className="form-group">
                                <label>Tên khoa học (nhập tay):</label>
                                <input 
                                    type="text" 
                                    name="scientificName" 
                                    value={newSpeciesData.scientificName} 
                                    onChange={handleManualNewSpeciesChange} 
                                    placeholder="Nhập tên khoa học" 
                                />
                            </div>
                        </>
                    )}
                </div>
            </section>
        )}
        
        <div className="form-actions">
          <button type="submit" className="submit-button">Lưu thay đổi</button>
          <button type="button" onClick={() => navigate(-1)} className="cancel-button">Hủy</button>
        </div>
      </form>
    </div>
  );
}

export default FarmEditPage;
